const crypto = require('crypto');
const secret = $env.REVIEW_HMAC_SECRET || 'fallback-secret';

const params = $input.first().json.query || {};
const action = params.action;
const docId  = params.doc_id;
const token  = params.token;

if (!action || !docId || !token) {
  return [{ json: { valid: false, error: 'Missing required parameters', action, docId } }];
}

const expected = crypto.createHmac('sha256', secret)
  .update(`${docId}|${action}`)
  .digest('hex');

const valid = expected === token;
return [{ json: { valid, action, docId: parseInt(docId), token } }];

