UPDATE core.tax_documents
SET review_status  = 'CONFIRMED',
    reviewer_notes = COALESCE(reviewer_notes, 'Confirmed via email review bot')
WHERE doc_id = {{ $json.docId }}
  AND review_status NOT IN ('CONFIRMED', 'REJECTED')
RETURNING doc_id, supplier_name, review_status;

UPDATE core.tax_documents
SET review_status  = 'REJECTED',
    reviewer_notes = COALESCE(reviewer_notes, 'Rejected via email review bot')
WHERE doc_id = {{ $json.docId }}
  AND review_status NOT IN ('CONFIRMED', 'REJECTED')
RETURNING doc_id, supplier_name, review_status;

