const row = $input.first().json;
const isConfirm = row.review_status === 'CONFIRMED';
const supplier = row.supplier_name || `Doc #${row.doc_id}`;
const alreadyDone = !row.doc_id; // RETURNING returned nothing = was already actioned

const icon    = isConfirm ? '✓' : '✗';
const colour  = isConfirm ? '#22c55e' : '#ef4444';
const verb    = isConfirm ? 'Confirmed' : 'Rejected';
const message = alreadyDone
  ? 'This record has already been actioned — no change made.'
  : `${supplier} has been marked as <strong>${verb}</strong>.`;

const html = `<!DOCTYPE html>
<html>
<head><meta name="viewport" content="width=device-width,initial-scale=1"></head>
<body style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;margin:0;padding:40px 20px;background:#f9fafb;text-align:center">
  <div style="max-width:400px;margin:0 auto;background:#fff;border-radius:12px;box-shadow:0 2px 8px rgba(0,0,0,.1);padding:40px 32px">
    <div style="width:64px;height:64px;border-radius:50%;background:${colour};margin:0 auto 20px;display:flex;align-items:center;justify-content:center">
      <span style="color:#fff;font-size:32px;line-height:1">${icon}</span>
    </div>
    <h2 style="margin:0 0 12px;color:#111">${verb}</h2>
    <p style="color:#555;margin:0 0 24px;font-size:15px">${message}</p>
    <a href="http://hal-srvr:3002/dashboard/6" style="background:#1e40af;color:#fff;padding:10px 20px;border-radius:6px;text-decoration:none;font-size:14px;font-weight:600">Open Review Queue</a>
  </div>
</body>
</html>`;

return [{ json: { html } }];
